import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"仁寿殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/renshou-dian.md","filePath":"landmarks/summer-palace/renshou-dian.md","lastUpdated":1784720050000}'),o={name:"landmarks/summer-palace/renshou-dian.md"};function n(i,t,s,d,h,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="仁寿殿" tabindex="-1">仁寿殿 <a class="header-anchor" href="#仁寿殿" aria-label="Permalink to &quot;仁寿殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1586788630595-bbd71f6f8646?w=1200&amp;q=80" alt="仁寿殿"></p><blockquote><p>&quot;仁者寿，德者昌。&quot; —— 一座殿堂，半部晚清史</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>仁寿殿位于颐和园东宫门内，是颐和园政治活动区的正殿，也是整座园林的权力中心。它始建于乾隆十五年（1750年），原名&quot;勤政殿&quot;，取《尚书》&quot;君王勤政，勤在于政&quot;之意；光绪年间重建时改名&quot;仁寿殿&quot;，语出《论语·雍也》&quot;仁者寿&quot;，寓意仁德之君得以长寿久治。</p><p>1886年颐和园重建后，这里成为紫禁城之外的另一处&quot;朝廷&quot;。从1886年到1908年，慈禧太后与光绪皇帝每年大部分时间驻跸颐和园，在此召见王公大臣、接见外国使节、处理军国大事。</p><p>许多改变近代中国走向的大事都在这座殿宇里发生：戊戌变法期间，光绪帝在仁寿殿召见康有为，破格委以总理衙门章京；百日维新夭折后，慈禧又在此垂帘训政十余年。</p><p>如今殿内陈设基本保持光绪朝原状，一器一物皆有来历。想读懂晚清最后二十年的宫廷政治，仁寿殿是最直观的现场。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆十五年（1750）</td><td style="text-align:left;">建勤政殿，为清漪园处理政务之所</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">随清漪园遭英法联军焚毁</td></tr><tr><td style="text-align:left;">光绪十二年（1886）</td><td style="text-align:left;">重建并更名&quot;仁寿殿&quot;，成为晚清政治中心</td></tr><tr><td style="text-align:left;">光绪二十四年（1898）</td><td style="text-align:left;">光绪帝召见康有为；戊戌政变后慈禧于此训政</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">随颐和园正式对公众开放</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>始建年代</strong></td><td style="text-align:left;">清乾隆十五年（1750年）</td></tr><tr><td style="text-align:left;"><strong>重建年代</strong></td><td style="text-align:left;">清光绪十二年（1886年）</td></tr><tr><td style="text-align:left;"><strong>建筑形制</strong></td><td style="text-align:left;">面阔七间，卷棚歇山顶，前后出廊</td></tr><tr><td style="text-align:left;"><strong>殿前陈设</strong></td><td style="text-align:left;">铜龙、铜凤、铜麒麟、太平有象、铜鹤、铜鹿等祥瑞铜兽</td></tr><tr><td style="text-align:left;"><strong>殿内陈设</strong></td><td style="text-align:left;">九龙宝座、御案、掌扇、屏风、自鸣钟、珐琅香炉</td></tr><tr><td style="text-align:left;"><strong>等级规制</strong></td><td style="text-align:left;">颐和园中等级最高的殿宇，黄琉璃瓦覆顶</td></tr></tbody></table><p>殿前月台之上，铜兽成对列置：龙、凤、麒麟、太平有象，寓意天下太平、祥瑞咸集；铜鹤、铜鹿侍立两翼，象征&quot;鹤鹿同春&quot;。</p><p>月台中央的铜鼎香炉为乾隆朝原物，历经英法联军大火而幸存，是园中为数不多的清漪园遗物。殿内正中设九龙宝座，宝座上方悬&quot;大圆宝镜&quot;匾，两侧掌扇、宫灯俱全，一派皇家威仪。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="凤在上-龙在下" tabindex="-1">凤在上，龙在下 <a class="header-anchor" href="#凤在上-龙在下" aria-label="Permalink to &quot;凤在上，龙在下&quot;">​</a></h3><p>按照宫廷礼制，龙象征皇帝，当居中；凤象征皇后，应列于两侧。然而仁寿殿前的铜凤却居中昂首，铜龙反而退居两侧——这是慈禧太后垂帘听政时期的刻意安排。</p><p>1886年重建后，慈禧命工匠将龙凤位置对调，以&quot;凤压龙&quot;的格局宣示自己才是这座园林乃至这个帝国的真正主人。一器一物，皆是权力的注脚。</p><h3 id="戊戌风云的起点" tabindex="-1">戊戌风云的起点 <a class="header-anchor" href="#戊戌风云的起点" aria-label="Permalink to &quot;戊戌风云的起点&quot;">​</a></h3><p>光绪二十四年四月二十八日（1898年6月16日），光绪帝在仁寿殿召见康有为，长谈两个多小时，当场破格授其总理衙门章京、许专折奏事。此后百日之内，变法诏书从仁寿殿一道道发出：废八股、设学堂、裁冗衙……维新派以为抓住了天子，却不知帘后的慈禧早已按下了政变的倒计时。八月，慈禧自仁寿殿还宫发动政变，光绪帝被囚于附近的<a href="/beijing-travel-guide/landmarks/summer-palace/">玉澜堂</a>，谭嗣同等&quot;戊戌六君子&quot;血洒菜市口。从召见到囚禁，不过百日，仁寿殿把近代史最惊心动魄的一章演完了。</p><h3 id="垂帘训政的十年" tabindex="-1">垂帘训政的十年 <a class="header-anchor" href="#垂帘训政的十年" aria-label="Permalink to &quot;垂帘训政的十年&quot;">​</a></h3><p>戊戌政变后，慈禧以&quot;训政&quot;之名重掌大权。仁寿殿的朝会从此变成固定的双座格局：光绪帝坐于殿中御座，如同木偶；慈禧坐在宝座侧后的屏风旁，群臣奏对须先听帘后发话。据时人笔记，光绪在仁寿殿几乎不发一言，一切政事&quot;皆太后意&quot;。这样的朝会持续了十年，直到1908年光绪、慈禧先后离世。殿前那尊&quot;凤压龙&quot;的铜器，原是权力的隐喻，最终成了命运的谶语。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>殿前铜兽阵列</strong>：龙、凤、麒麟、太平有象一应俱全，注意观察&quot;凤上龙下&quot;的特殊格局，全园独此一处。</li><li><strong>九龙宝座与御案</strong>：殿内陈设为光绪朝原状，宝座、屏风、掌扇保存完好，可直观感受晚清宫廷气象。</li><li><strong>乾隆朝铜鼎</strong>：殿前铜鼎香炉是清漪园旧物，躲过了1860年的大火，是园林沧桑的活见证。</li><li><strong>寿星石</strong>：殿前庭院中的太湖石形似老寿星，相传为米万钟&quot;败家石&quot;遗脉，玲珑剔透，耐人寻味。</li><li><strong>大圆宝镜匾</strong>：宝座上方御匾与殿内西洋自鸣钟同框，是&quot;中学为体、西学为用&quot;在宫廷陈设上的微妙体现。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>铜兽特写</strong>：以铜凤为中心构图，背景收入仁寿殿匾额，清晨侧光下铜器泛着幽光。</li><li><strong>月台仰拍</strong>：从月台西南角低角度仰拍飞檐，突出皇家殿宇的压迫感。</li><li><strong>庭院纵深</strong>：以寿星石为前景，透过门洞拍仁寿殿全景，&quot;框景&quot;效果一流。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>仁寿殿紧邻东宫门，走<a href="/beijing-travel-guide/landmarks/summer-palace/">东宫门线</a>的游客会最先抵达，建议开园即入，人少时光线也最适合拍照。</li><li>殿内光线较暗，禁止闪光灯，想看清九龙宝座细节可稍作停留适应光线。</li><li>殿外月台和铜兽区是游客合影热点，清晨和傍晚前后人流相对疏散。</li><li>游览完仁寿殿，可顺路参观北侧的<a href="/beijing-travel-guide/landmarks/summer-palace/dehe-yuan.html">德和园</a>，了解慈禧的另一面日常——看戏。</li><li>政治活动区与<a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a>、<a href="/beijing-travel-guide/landmarks/summer-palace/foxiang-ge.html">佛香阁</a>所在的游览区之间，只隔一道乐寿堂，动线衔接顺畅。</li><li>殿前铜兽禁止触摸攀爬，百年青铜经不起手汗侵蚀，远观即是最高的敬意。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：仁寿殿需要单独购票吗？</strong></p><p>不需要。仁寿殿所在的颐和园政治活动区包含在大门票内，购大门票或联票均可进入。</p><p><strong>Q：殿内可以进去参观吗？</strong></p><p>不能入内。殿门口设有护栏，游客只能在门外隔栏观看殿内陈设，且殿内禁止拍照。</p><p><strong>Q：&quot;凤在上龙在下&quot;具体怎么看？</strong></p><p>看殿前月台上的铜兽：铜凤居于前排正中位置，铜龙退居两侧，与常规礼制相反，是慈禧权势的物证。</p><p><strong>Q：仁寿殿附近还有什么值得一看的？</strong></p><p>北侧<a href="/beijing-travel-guide/landmarks/summer-palace/dehe-yuan.html">德和园</a>是慈禧看戏之所，南侧玉澜堂是光绪帝被囚之处，两处与仁寿殿合看，晚清政治史就齐了。</p><hr><p><strong>📍 位置</strong>：颐和园东部政治活动区，东宫门内北侧 <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',39)])])}const q=a(o,[["render",n]]);export{p as __pageData,q as default};
